return ['domain'=>'capability-manager-enhanced','plural-forms'=>'nplurals=1; plural=0;','language'=>'id-ID','project-id-version'=>'PublishPress Capabilities 2.40.0','pot-creation-date'=>'2026-03-23T21:48:55+00:00','po-revision-date'=>'2026-04-22 08:33+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['PublishPress Capabilities'=>'PublishPress Capabilities','https://publishpress.com/capability-manager/'=>'https://publishpress.com/capability-manager/','PublishPress Capabilities is the access control plugin for WordPress. You can manage all your WordPress user roles, from Administrators to Subscribers.'=>'Kemampuan PublishPress adalah plugin kontrol akses untuk WordPress. Anda dapat mengelola semua peran pengguna WordPress Anda, dari Administrator hingga Pelanggan.','PublishPress'=>'PublishPress','https://publishpress.com/'=>'https://publishpress.com/','%1s Error: %2s  PublishPress Capabilities cannot function because another copy of the plugin is active.'=>'%1s Galat: %2s PublishPress Capabilities tidak dapat berfungsi karena salinan lain dari plugin ini aktif.','This plugin can be deleted.'=>'Plugin ini bisa dihapus.','You can block pages by URL or hide Admin elements by entering a CSS class or ID. This feature is available in PublishPress Capabilities Pro.'=>'Anda dapat memblokir halaman berdasarkan URL atau menyembunyikan elemen Admin dengan memasukkan kelas atau ID CSS. Fitur ini tersedia dalam PublishPress Capabilities Pro.','Upgrade to Pro'=>'Upgrade ke Pro','Admin Menu Restrictions'=>'Pembatasan Menu Admin','You can restrict access to admin menu screens. You can also edit, change, add, or remove links from the WordPress admin menu. This feature is available in PublishPress Capabilities Pro.'=>'Anda dapat membatasi akses ke layar menu admin. Anda juga dapat mengedit, mengubah, menambahkan, atau menghapus tautan dari menu admin WordPress. Fitur ini tersedia di PublishPress Capabilities Pro.','You\'re using PublishPress Capabilities Free. The Pro vers